def test_manifest_uvicorn_starlette_client_abort_cancels_streaming_response():
    before_status = omnivm.status()
    before_boundary = before_status.get("boundary", {})
    before_handles = before_status.get("handles", {})
    port = free_tcp_port()
    setup = f'''
import asyncio
import socket
import struct
import threading
import time
import uvicorn
from starlette.applications import Starlette
from starlette.responses import StreamingResponse
from starlette.routing import Route

uvicorn_abort_req = None
uvicorn_abort_events = []
body_done = threading.Event()
port = {port!r}

async def endpoint(request):
    global uvicorn_abort_req
    uvicorn_abort_req = request
    marker = omnivm.call(
        "javascript",
        "omnivm.call('python', 'uvicorn_abort_req.method') + ':' + "
        "omnivm.call('python', 'uvicorn_abort_req.url.path')",
    )
    if marker != "GET:/asgi/server-abort":
        uvicorn_abort_events.append("bad-marker:" + str(marker))

    async def body():
        uvicorn_abort_events.append("body-started")
        try:
            yield b"first\\n"
            await asyncio.sleep(5)
            uvicorn_abort_events.append("second-yield-ok")
            yield b"second\\n"
        except BaseException as exc:
            uvicorn_abort_events.append("body-closed:" + type(exc).__name__)
            raise
        finally:
            uvicorn_abort_events.append("body-cleanup")
            body_done.set()

    return StreamingResponse(body(), status_code=200, headers={{"X-Stream": "uvicorn"}})

app = Starlette(routes=[Route("/asgi/server-abort", endpoint, methods=["GET"])])
config = uvicorn.Config(
    app,
    host="127.0.0.1",
    port=port,
    log_level="critical",
    access_log=False,
    lifespan="off",
)
server = uvicorn.Server(config)

def serve():
    try:
        asyncio.run(server.serve())
    except BaseException as exc:
        uvicorn_abort_events.append("server-error:" + type(exc).__name__ + ":" + str(exc))

server_thread = threading.Thread(target=serve)
server_thread.start()
deadline = time.time() + 5
while not server.started and time.time() < deadline:
    if any(event.startswith("server-error:") for event in uvicorn_abort_events):
        break
    time.sleep(0.01)
if not server.started:
    server.should_exit = True
    server_thread.join(timeout=5)
    raise AssertionError(f"uvicorn server did not start: {{uvicorn_abort_events!r}}")

sock = socket.create_connection(("127.0.0.1", port), timeout=5)
try:
    sock.sendall(
        b"GET /asgi/server-abort HTTP/1.1\\r\\n"
        b"Host: 127.0.0.1\\r\\n"
        b"X-Request-Id: uvicorn-abort-42\\r\\n"
        b"Connection: close\\r\\n\\r\\n"
    )
    data = b""
    deadline = time.time() + 5
    while b"first" not in data and time.time() < deadline:
        chunk = sock.recv(1024)
        if not chunk:
            break
        data += chunk
    if b"first" not in data:
        uvicorn_abort_events.append("client-missed-first")
    sock.setsockopt(socket.SOL_SOCKET, socket.SO_LINGER, struct.pack("ii", 1, 0))
finally:
    sock.close()

deadline = time.time() + 5
while not body_done.is_set() and time.time() < deadline:
    time.sleep(0.01)

server.should_exit = True
server_thread.join(timeout=5)
if server_thread.is_alive():
    raise AssertionError(f"uvicorn server thread did not stop: {{uvicorn_abort_events!r}}")
if any(event.startswith("server-error:") for event in uvicorn_abort_events):
    raise AssertionError(f"uvicorn server failed: {{uvicorn_abort_events!r}}")
if not body_done.is_set():
    raise AssertionError(f"uvicorn streaming body did not clean up after client abort: {{uvicorn_abort_events!r}}")
'''
    verify = r'''
if uvicorn_abort_req is None:
    raise AssertionError("uvicorn Starlette request was never captured")
if any(event.startswith("bad-marker:") for event in uvicorn_abort_events):
    raise AssertionError(f"uvicorn request was not visible through JS/Python re-entry: {uvicorn_abort_events!r}")
if "client-missed-first" in uvicorn_abort_events:
    raise AssertionError(f"uvicorn abort client did not observe first chunk: {uvicorn_abort_events!r}")
if "body-started" not in uvicorn_abort_events:
    raise AssertionError(f"uvicorn streaming body did not start: {uvicorn_abort_events!r}")
if "body-cleanup" not in uvicorn_abort_events:
    raise AssertionError(f"uvicorn streaming body did not clean up: {uvicorn_abort_events!r}")
if "second-yield-ok" in uvicorn_abort_events:
    raise AssertionError(f"uvicorn streaming body continued after client abort: {uvicorn_abort_events!r}")
if not any(event.startswith("body-closed:") for event in uvicorn_abort_events):
    raise AssertionError(f"uvicorn streaming body did not observe close/cancel: {uvicorn_abort_events!r}")
'''
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {"op": "exec", "runtime": "python", "code": setup},
            {
                "op": "exec",
                "runtime": "javascript",
                "captures": {"uvicorn_abort_req": "uvicorn_abort_req"},
                "code": (
                    "if (uvicorn_abort_req.method !== 'GET') throw new Error('bad Uvicorn request method: ' + uvicorn_abort_req.method); "
                    "if (uvicorn_abort_req.url.path !== '/asgi/server-abort') throw new Error('bad Uvicorn request path: ' + uvicorn_abort_req.url.path); "
                    "if (uvicorn_abort_req.headers.get('x-request-id') !== 'uvicorn-abort-42') "
                    "throw new Error('bad Uvicorn request header: ' + uvicorn_abort_req.headers.get('x-request-id'));"
                ),
            },
            {"op": "exec", "runtime": "python", "code": verify},
        ],
    }
    run_manifest_dict(manifest)

    after_status = omnivm.status()
    after_boundary = after_status.get("boundary", {})
    after_handles = after_status.get("handles", {})
    if after_boundary.get("resource_proxy_captures", 0) < 1:
        raise AssertionError(f"Uvicorn Starlette request did not cross as live proxy: before={before_boundary}, after={after_boundary}")
    if after_boundary.get("stream_proxy_captures", 0) != before_boundary.get("stream_proxy_captures", 0):
        raise AssertionError(f"Uvicorn Starlette request crossed as a stream: before={before_boundary}, after={after_boundary}")
    if after_boundary.get("json_fallbacks", 0) != before_boundary.get("json_fallbacks", 0):
        raise AssertionError(f"Uvicorn Starlette request used JSON fallback: before={before_boundary}, after={after_boundary}")
    if after_handles.get("handle_accesses_by_kind", {}).get("property", 0) <= before_handles.get("handle_accesses_by_kind", {}).get("property", 0):
        raise AssertionError(f"Uvicorn Starlette request proxy did not record JS property access: before={before_handles}, after={after_handles}")
    if after_handles.get("live", 0) > before_handles.get("live", 0):
        raise AssertionError(f"Uvicorn Starlette abort leaked handles: before={before_handles}, after={after_handles}")


def test_manifest_starlette_streaming_response_body_iterator_is_lazy_and_cancellable():
    before_status = omnivm.status()
    before_boundary = before_status.get("boundary", {})
    before_handles = before_status.get("handles", {})
    setup = r'''
import asyncio
from starlette.responses import StreamingResponse

stream_state = {"started": 0, "closed": False}

async def streaming_body():
    stream_state["started"] += 1
    try:
        yield b"first"
        yield b"second"
    finally:
        stream_state["closed"] = True

starlette_loop = asyncio.new_event_loop()
asyncio.set_event_loop(starlette_loop)
globals()["__omnivm_stream_loop"] = starlette_loop
resp = StreamingResponse(streaming_body(), status_code=202, headers={"X-Stream": "yes"})
'''
    verify = r'''
if stream_state["started"] != 1:
    raise AssertionError(f"streaming body iteration count was wrong: {stream_state!r}")
if not stream_state["closed"]:
    raise AssertionError("streaming response body did not close after JS cancel")
starlette_loop.close()
'''
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {"op": "exec", "runtime": "python", "code": setup},
            {
                "op": "exec",
                "runtime": "javascript",
                "captures": {"resp": "resp"},
                "code": (
                    "if (String(resp.status_code) !== '202') throw new Error('bad Starlette response status: ' + resp.status_code); "
                    "const header = resp.headers.get ? resp.headers.get('x-stream') : (resp.headers['x-stream'] || resp.headers['X-Stream']); "
                    "if (header !== 'yes') throw new Error('bad Starlette response header: ' + header); "
                    "const body = resp.body_iterator; "
                    "if (!body || typeof body[Symbol.iterator] !== 'function') throw new Error('body_iterator did not materialize as stream'); "
                    "const it = body[Symbol.iterator](); "
                    "const first = it.next(); "
                    "const asText = (value) => typeof value === 'string' ? value : String.fromCharCode(...Array.from(value)); "
                    "if (first.done || asText(first.value) !== 'first') throw new Error('bad Starlette first body chunk: ' + JSON.stringify(first)); "
                    "body.cancel('client-abort');"
                ),
            },
            {"op": "exec", "runtime": "python", "code": verify},
        ],
    }
    run_manifest_dict(manifest)

    after_status = omnivm.status()
    boundary = after_status.get("boundary", {})
    handles = after_status.get("handles", {})
    if boundary.get("resource_proxy_captures", 0) < 1:
        raise AssertionError(f"Starlette StreamingResponse lost live response proxy state: before={before_boundary}, after={boundary}")
    if boundary.get("stream_proxy_captures", 0) < 1:
        raise AssertionError(f"Starlette StreamingResponse body_iterator did not cross as stream proxy: before={before_boundary}, after={boundary}")
    if boundary.get("json_fallbacks", 0) != 0:
        raise AssertionError(f"Starlette StreamingResponse used JSON fallback: before={before_boundary}, after={boundary}")
    if handles.get("explicit_releases", 0) < 1:
        raise AssertionError(f"Starlette StreamingResponse body stream did not release on cancel: before={before_handles}, after={handles}")


def test_manifest_aiohttp_web_response_capture_uses_proxy_not_stream():
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {
                "op": "eval",
                "runtime": "python",
                "bind": "aiohttp_resp",
                "code": (
                    "(__import__('aiohttp.web', fromlist=['Response']).Response("
                    "status=207, text='hello-aiohttp', headers={'X-Aiohttp': 'yes'}))"
                ),
            },
            {
                "op": "exec",
                "runtime": "javascript",
                "captures": {"aiohttp_resp": "aiohttp_resp"},
                "code": (
                    "if (String(aiohttp_resp.status) !== '207') throw new Error('bad aiohttp status: ' + aiohttp_resp.status); "
                    "if (aiohttp_resp.text !== 'hello-aiohttp') throw new Error('bad aiohttp text: ' + aiohttp_resp.text); "
                    "const header = aiohttp_resp.headers.get ? aiohttp_resp.headers.get('X-Aiohttp') : aiohttp_resp.headers['X-Aiohttp']; "
                    "if (header !== 'yes') throw new Error('bad aiohttp header: ' + header); "
                    "aiohttp_resp.headers['X-From-JS'] = 'yes';"
                ),
            },
            {
                "op": "exec",
                "runtime": "python",
                "captures": {"aiohttp_resp": "aiohttp_resp"},
                "code": (
                    "assert aiohttp_resp.status == 207, aiohttp_resp.status\n"
                    "assert aiohttp_resp.text == 'hello-aiohttp', aiohttp_resp.text\n"
                    "assert aiohttp_resp.headers['X-From-JS'] == 'yes', aiohttp_resp.headers"
                ),
            },
        ],
    }
    run_manifest_dict(manifest)

    boundary = omnivm.status().get("boundary", {})
    handles = omnivm.status().get("handles", {})
    if boundary.get("resource_proxy_captures", 0) < 1:
        raise AssertionError(f"aiohttp web response did not cross as a live proxy: {boundary}")
    if boundary.get("stream_proxy_captures", 0) != 0:
        raise AssertionError(f"aiohttp web response crossed as a stream: {boundary}")
    if boundary.get("json_fallbacks", 0) != 0:
        raise AssertionError(f"aiohttp web response used JSON fallback: {boundary}")
    for kind in ("property", "mutation"):
        if handles.get("handle_accesses_by_kind", {}).get(kind, 0) < 1:
            raise AssertionError(f"aiohttp web response proxy did not record {kind} access: {handles}")


def test_manifest_aiohttp_server_client_abort_cleans_up_streaming_response():
    before_status = omnivm.status()
    before_boundary = before_status.get("boundary", {})
    before_handles = before_status.get("handles", {})
    port = free_tcp_port()
    setup = f'''
import asyncio
import socket
import struct
import threading
import time
from aiohttp import web

aiohttp_server_req = None
aiohttp_abort_events = []
server_done = threading.Event()
port = {port!r}

async def handler(request):
    global aiohttp_server_req
    aiohttp_server_req = request
    try:
        marker = omnivm.call(
            "javascript",
            "omnivm.call('python', 'aiohttp_server_req.method') + ':' + "
            "omnivm.call('python', 'aiohttp_server_req.path')",
        )
        if marker != "GET:/aiohttp/server-abort":
            aiohttp_abort_events.append("bad-marker:" + str(marker))
        resp = web.StreamResponse(status=200, headers={{"Content-Type": "text/plain"}})
        await resp.prepare(request)
        await resp.write(b"first\\n")
        await asyncio.sleep(0.2)
        transport = request.transport
        if transport is not None and transport.is_closing():
            aiohttp_abort_events.append("transport-closing")
        await resp.write(b"second\\n")
        aiohttp_abort_events.append("second-write-ok")
    except (ConnectionResetError, ConnectionError, RuntimeError, BrokenPipeError) as exc:
        aiohttp_abort_events.append("write-aborted:" + type(exc).__name__)
    finally:
        aiohttp_abort_events.append("cleanup")
        server_done.set()
    return resp

async def run_server_probe():
    app = web.Application()
    app.router.add_get("/aiohttp/server-abort", handler)
    runner = web.AppRunner(app)
    await runner.setup()
    site = web.TCPSite(runner, "127.0.0.1", port)
    await site.start()

    def client_abort():
        sock = socket.create_connection(("127.0.0.1", port), timeout=5)
        try:
            sock.sendall(
                b"GET /aiohttp/server-abort HTTP/1.1\\r\\n"
                b"Host: 127.0.0.1\\r\\n"
                b"X-Request-Id: aiohttp-abort-42\\r\\n"
                b"Connection: close\\r\\n\\r\\n"
            )
            data = b""
            deadline = time.time() + 5
            while b"first" not in data and time.time() < deadline:
                chunk = sock.recv(1024)
                if not chunk:
                    break
                data += chunk
            if b"first" not in data:
                aiohttp_abort_events.append("client-missed-first")
            sock.setsockopt(socket.SOL_SOCKET, socket.SO_LINGER, struct.pack("ii", 1, 0))
        finally:
            sock.close()

    client = threading.Thread(target=client_abort)
    client.start()
    deadline = time.time() + 5
    while not server_done.is_set() and time.time() < deadline:
        await asyncio.sleep(0.01)
    client.join(timeout=5)
    await runner.cleanup()

loop = asyncio.new_event_loop()
try:
    asyncio.set_event_loop(loop)
    loop.run_until_complete(run_server_probe())
finally:
    asyncio.set_event_loop(None)
    loop.close()

if not server_done.is_set():
    raise AssertionError(f"aiohttp server handler did not finish after client abort: {{aiohttp_abort_events!r}}")
'''
    verify = r'''
if aiohttp_server_req is None:
    raise AssertionError("aiohttp request was never captured by the handler")
if "cleanup" not in aiohttp_abort_events:
    raise AssertionError(f"aiohttp abort cleanup did not run: {aiohttp_abort_events!r}")
if any(event.startswith("bad-marker:") for event in aiohttp_abort_events):
    raise AssertionError(f"aiohttp request was not visible through JS/Python re-entry: {aiohttp_abort_events!r}")
if "client-missed-first" in aiohttp_abort_events:
    raise AssertionError(f"aiohttp abort client did not observe first chunk: {aiohttp_abort_events!r}")
if "second-write-ok" in aiohttp_abort_events:
    raise AssertionError(f"aiohttp second write succeeded after forced client abort: {aiohttp_abort_events!r}")
if not any(event == "transport-closing" or event.startswith("write-aborted:") for event in aiohttp_abort_events):
    raise AssertionError(f"aiohttp server did not observe client abort: {aiohttp_abort_events!r}")
'''
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {"op": "exec", "runtime": "python", "code": setup},
            {
                "op": "exec",
                "runtime": "javascript",
                "captures": {"aiohttp_server_req": "aiohttp_server_req"},
                "code": (
                    "if (aiohttp_server_req.method !== 'GET') throw new Error('bad aiohttp request method: ' + aiohttp_server_req.method); "
                    "if (aiohttp_server_req.path !== '/aiohttp/server-abort') throw new Error('bad aiohttp request path: ' + aiohttp_server_req.path); "
                    "if (aiohttp_server_req.headers.get('X-Request-Id') !== 'aiohttp-abort-42') "
                    "throw new Error('bad aiohttp request header: ' + aiohttp_server_req.headers.get('X-Request-Id'));"
                ),
            },
            {"op": "exec", "runtime": "python", "code": verify},
        ],
    }
    run_manifest_dict(manifest)

    after_status = omnivm.status()
    after_boundary = after_status.get("boundary", {})
    after_handles = after_status.get("handles", {})
    if after_boundary.get("resource_proxy_captures", 0) < 1:
        raise AssertionError(f"aiohttp server request did not cross as live proxy: before={before_boundary}, after={after_boundary}")
    if after_boundary.get("stream_proxy_captures", 0) != before_boundary.get("stream_proxy_captures", 0):
        raise AssertionError(f"aiohttp server request crossed as a stream: before={before_boundary}, after={after_boundary}")
    if after_boundary.get("json_fallbacks", 0) != before_boundary.get("json_fallbacks", 0):
        raise AssertionError(f"aiohttp server request used JSON fallback: before={before_boundary}, after={after_boundary}")
    if after_handles.get("handle_accesses_by_kind", {}).get("property", 0) <= before_handles.get("handle_accesses_by_kind", {}).get("property", 0):
        raise AssertionError(f"aiohttp server request proxy did not record JS property access: before={before_handles}, after={after_handles}")
    if after_handles.get("live", 0) > before_handles.get("live", 0):
        raise AssertionError(f"aiohttp server abort leaked handles: before={before_handles}, after={after_handles}")


def test_manifest_aiohttp_stream_response_write_after_eof_reports_owner_error():
    before_status = omnivm.status()
    before_boundary = before_status.get("boundary", {})
    before_handles = before_status.get("handles", {})
    port = free_tcp_port()
    setup = f'''
import asyncio
from aiohttp import web

aiohttp_closed_stream_response = None
aiohttp_closed_writer_events = []
port = {port!r}

async def handler(request):
    global aiohttp_closed_stream_response
    resp = web.StreamResponse(status=208, headers={{"Content-Type": "text/plain"}})
    aiohttp_closed_stream_response = resp
    await resp.prepare(request)
    await resp.write(b"first")
    await resp.write_eof()
    aiohttp_closed_writer_events.append("write-eof")
    return resp

async def run_aiohttp_closed_writer_probe():
    app = web.Application()
    app.router.add_get("/aiohttp/write-after-eof", handler)
    runner = web.AppRunner(app)
    await runner.setup()
    site = web.TCPSite(runner, "127.0.0.1", port)
    await site.start()
    reader, writer = await asyncio.open_connection("127.0.0.1", port)
    writer.write(
        b"GET /aiohttp/write-after-eof HTTP/1.1\\r\\n"
        b"Host: 127.0.0.1\\r\\n"
        b"Connection: close\\r\\n\\r\\n"
    )
    await writer.drain()
    data = await reader.read()
    writer.close()
    await writer.wait_closed()
    await runner.cleanup()
    if b"first" not in data:
        raise AssertionError(f"aiohttp closed-writer client missed body bytes: {{data!r}}")

aiohttp_closed_writer_loop = asyncio.new_event_loop()
globals()["__omnivm_stream_loop"] = aiohttp_closed_writer_loop
try:
    asyncio.set_event_loop(aiohttp_closed_writer_loop)
    aiohttp_closed_writer_loop.run_until_complete(run_aiohttp_closed_writer_probe())
finally:
    asyncio.set_event_loop(None)
'''
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {"op": "exec", "runtime": "python", "code": setup},
            {
                "op": "exec",
                "runtime": "javascript",
                "captures": {
                    "aiohttp_closed_stream_response": "aiohttp_closed_stream_response",
                },
                "code": (
                    "globalThis.aiohttpClosedStreamResponse = aiohttp_closed_stream_response; "
                    "if (String(aiohttpClosedStreamResponse.status) !== '208') throw new Error('bad aiohttp closed-writer status: ' + aiohttpClosedStreamResponse.status); "
                    "if (typeof aiohttpClosedStreamResponse.write !== 'function') throw new Error('aiohttp StreamResponse lost write method');"
                ),
            },
            {
                "op": "exec",
                "runtime": "javascript",
                "async": True,
                "code": (
                    "let failed = false; "
                    "try { "
                    "  await globalThis.aiohttpClosedStreamResponse.write(new Uint8Array([108, 97, 116, 101])); "
                    "} catch (err) { "
                    "  globalThis.aiohttpLateWriteError = {name: err && err.name, message: err && err.message}; "
                    "  failed = String(err && err.message || err).includes('Cannot call write() after write_eof()'); "
                    "} "
                    "if (!failed) throw new Error('aiohttp StreamResponse write after EOF did not report owner error: ' + JSON.stringify(globalThis.aiohttpLateWriteError));"
                ),
            },
            {
                "op": "exec",
                "runtime": "python",
                "code": (
                    "if aiohttp_closed_stream_response is None:\n"
                    "    raise AssertionError('aiohttp closed StreamResponse was not captured')\n"
                    "if not aiohttp_closed_stream_response.prepared:\n"
                    "    raise AssertionError('aiohttp closed StreamResponse lost prepared state')\n"
                    "if 'write-eof' not in aiohttp_closed_writer_events:\n"
                    "    raise AssertionError(f'aiohttp StreamResponse did not reach write_eof: {aiohttp_closed_writer_events!r}')\n"
                    "aiohttp_closed_writer_loop.close()"
                ),
            },
        ],
    }
    run_manifest_dict(manifest)

    after_status = omnivm.status()
    boundary = after_status.get("boundary", {})
    handles = after_status.get("handles", {})
    if boundary.get("resource_proxy_captures", 0) < before_boundary.get("resource_proxy_captures", 0):
        raise AssertionError(f"aiohttp closed StreamResponse resource proxy counter regressed: before={before_boundary}, after={boundary}")
    if boundary.get("stream_proxy_captures", 0) != before_boundary.get("stream_proxy_captures", 0):
        raise AssertionError(f"aiohttp closed StreamResponse crossed as a stream: before={before_boundary}, after={boundary}")
    if boundary.get("table_proxy_captures", 0) < before_boundary.get("table_proxy_captures", 0) + 1:
        raise AssertionError(f"aiohttp closed StreamResponse JS byte write did not use a table-backed byte argument: before={before_boundary}, after={boundary}")
    if boundary.get("arrow_transfers", 0) < before_boundary.get("arrow_transfers", 0) + 1:
        raise AssertionError(f"aiohttp closed StreamResponse JS byte write did not use Arrow/shared memory: before={before_boundary}, after={boundary}")
    if boundary.get("json_fallbacks", 0) != before_boundary.get("json_fallbacks", 0):
        raise AssertionError(f"aiohttp closed StreamResponse used JSON fallback: before={before_boundary}, after={boundary}")
    if handles.get("handle_accesses_by_kind", {}).get("call", 0) < before_handles.get("handle_accesses_by_kind", {}).get("call", 0) + 1:
        raise AssertionError(f"aiohttp closed StreamResponse write call was not recorded: before={before_handles}, after={handles}")
    if handles.get("live", 0) > before_handles.get("live", 0):
        raise AssertionError(f"aiohttp closed StreamResponse leaked handles: before={before_handles}, after={handles}")


def test_manifest_werkzeug_wsgi_writer_after_close_reports_owner_error():
    before_status = omnivm.status()
    before_boundary = before_status.get("boundary", {})
    before_handles = before_status.get("handles", {})
    port = free_tcp_port()
    setup = f'''
import socket
import threading
import time

from werkzeug.serving import make_server

werkzeug_closed_writer = None
werkzeug_closed_writer_events = []
port = {port!r}

def wsgi_app(environ, start_response):
    global werkzeug_closed_writer
    write = start_response("209 Custom", [("Content-Type", "text/plain"), ("X-Poly", "wsgi")])
    werkzeug_closed_writer = write
    werkzeug_closed_writer_events.append("handler")
    write(b"first")
    werkzeug_closed_writer_events.append("wrote-first")
    return [b"second"]

server = make_server("127.0.0.1", port, wsgi_app, threaded=False)
server_thread = threading.Thread(target=server.handle_request)
server_thread.start()

sock = socket.create_connection(("127.0.0.1", port), timeout=5)
try:
    sock.settimeout(1)
    sock.sendall(
        b"GET /werkzeug/write-after-close HTTP/1.1\\r\\n"
        b"Host: 127.0.0.1\\r\\n"
        b"Connection: close\\r\\n\\r\\n"
    )
    data = b""
    deadline = time.time() + 5
    while time.time() < deadline:
        try:
            chunk = sock.recv(4096)
        except socket.timeout:
            continue
        if not chunk:
            break
        data += chunk
    data_lower = data.lower()
    if b"209 custom" not in data_lower or b"x-poly: wsgi" not in data_lower or b"firstsecond" not in data:
        raise AssertionError(f"bad Werkzeug WSGI response bytes: {{data!r}}")
finally:
    sock.close()

server_thread.join(timeout=5)
server.server_close()

if server_thread.is_alive():
    raise AssertionError(f"Werkzeug WSGI server request thread did not stop: {{werkzeug_closed_writer_events!r}}")
if werkzeug_closed_writer is None:
    raise AssertionError("Werkzeug WSGI writer was never captured")
if werkzeug_closed_writer_events != ["handler", "wrote-first"]:
    raise AssertionError(f"bad Werkzeug WSGI writer events: {{werkzeug_closed_writer_events!r}}")
'''
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {"op": "exec", "runtime": "python", "code": setup},
            {
                "op": "exec",
                "runtime": "javascript",
                "captures": {"werkzeug_closed_writer": "werkzeug_closed_writer"},
                "code": (
                    "globalThis.werkzeugClosedWriter = werkzeug_closed_writer; "
                    "if (typeof werkzeugClosedWriter !== 'function') throw new Error('Werkzeug WSGI writer did not cross as callable');"
                ),
            },
            {
                "op": "exec",
                "runtime": "javascript",
                "code": (
                    "let failed = false; "
                    "try { "
                    "  globalThis.werkzeugClosedWriter(new Uint8Array([108, 97, 116, 101])); "
                    "} catch (err) { "
                    "  globalThis.werkzeugLateWriterError = {"
                    "    name: err && err.name, "
                    "    message: err && err.message, "
                    "    runtime: err && err.runtime, "
                    "    type: err && err.type, "
                    "    traceback: err && err.traceback, "
                    "    boundaryPath: err && err.boundaryPath"
                    "  }; "
                    "  failed = err && err.runtime === 'python' && err.type === 'OSError' && "
                    "    String(err.message || '').includes('Bad file descriptor') && "
                    "    String(err.traceback || '').includes('Traceback') && "
                    "    err.boundaryPath === 'call[python]'; "
                    "} "
                    "if (!failed) throw new Error('Werkzeug WSGI writer after close did not report owner OSError: ' + JSON.stringify(globalThis.werkzeugLateWriterError));"
                ),
            },
            {
                "op": "exec",
                "runtime": "python",
                "code": (
                    "assert werkzeug_closed_writer is not None\n"
                    "assert werkzeug_closed_writer_events == ['handler', 'wrote-first'], werkzeug_closed_writer_events"
                ),
            },
        ],
    }
    run_manifest_dict(manifest)

    after_status = omnivm.status()
    boundary = after_status.get("boundary", {})
    handles = after_status.get("handles", {})
    resource_captures = boundary.get("resource_proxy_captures", 0)
    resource_capture_delta = resource_captures - before_boundary.get("resource_proxy_captures", 0)
    if resource_captures < 1 and resource_capture_delta < 1:
        raise AssertionError(f"Werkzeug WSGI writer did not cross as live proxy: before={before_boundary}, after={boundary}")
    if boundary.get("stream_proxy_captures", 0) != before_boundary.get("stream_proxy_captures", 0):
        raise AssertionError(f"Werkzeug WSGI writer crossed as a stream: before={before_boundary}, after={boundary}")
    if boundary.get("json_fallbacks", 0) != before_boundary.get("json_fallbacks", 0):
        raise AssertionError(f"Werkzeug WSGI writer used JSON fallback: before={before_boundary}, after={boundary}")
    if handles.get("handle_accesses_by_kind", {}).get("call", 0) < before_handles.get("handle_accesses_by_kind", {}).get("call", 0) + 1:
        raise AssertionError(f"Werkzeug WSGI writer call was not recorded: before={before_handles}, after={handles}")


