def test_manifest_express_request_abort_lifecycle_stays_live():
    before_status = omnivm.status()
    before_handles = before_status.get("handles", {})
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {
                "op": "eval",
                "runtime": "javascript",
                "bind": "express_abort_req",
                "code": (
                    "(() => { "
                    "const express = require('express'); "
                    "const http = require('http'); "
                    "const req = new http.IncomingMessage(); "
                    "Object.setPrototypeOf(req, express.request); "
                    "req.app = express(); "
                    "req.method = 'POST'; "
                    "req.url = '/express/abort?mode=poly'; "
                    "req.headers = {'x-request-id': 'express-abort-42', 'host': 'example.test'}; "
                    "req.aborted = false; "
                    "globalThis.expressAbortState = {abortedEvents: 0, closeEvents: 0, reason: ''}; "
                    "req.on('aborted', () => { globalThis.expressAbortState.abortedEvents += 1; }); "
                    "req.on('close', () => { globalThis.expressAbortState.closeEvents += 1; }); "
                    "req.abortFromClient = function(reason) { "
                    "  this.aborted = true; "
                    "  globalThis.expressAbortState.reason = String(reason || ''); "
                    "  this.emit('aborted'); "
                    "  this.emit('close'); "
                    "  return this.aborted; "
                    "}; "
                    "globalThis.__omnivm_express_abort_req = req; "
                    "return req; "
                    "})()"
                ),
            },
            {
                "op": "exec",
                "runtime": "python",
                "captures": {"express_abort_req": "express_abort_req"},
                "code": (
                    "assert express_abort_req.method == 'POST', express_abort_req.method\n"
                    "assert express_abort_req.path == '/express/abort', express_abort_req.path\n"
                    "assert express_abort_req.get('x-request-id') == 'express-abort-42', express_abort_req.get('x-request-id')\n"
                    "assert express_abort_req.abortFromClient('client-abort') is True\n"
                    "assert express_abort_req.aborted is True, express_abort_req.aborted"
                ),
            },
            {
                "op": "exec",
                "runtime": "javascript",
                "code": (
                    "const req = globalThis.__omnivm_express_abort_req; "
                    "const state = globalThis.expressAbortState; "
                    "if (!req.aborted) throw new Error('Express request abort flag did not stay live'); "
                    "if (state.reason !== 'client-abort') throw new Error('bad abort reason: ' + state.reason); "
                    "if (state.abortedEvents !== 1) throw new Error('bad aborted event count: ' + state.abortedEvents); "
                    "if (state.closeEvents !== 1) throw new Error('bad close event count: ' + state.closeEvents);"
                ),
            },
        ],
    }
    run_manifest_dict(manifest)

    after_status = omnivm.status()
    boundary = after_status.get("boundary", {})
    handles = after_status.get("handles", {})
    if boundary.get("resource_proxy_captures", 0) < 1:
        raise AssertionError(f"Express abort request did not cross as a live proxy: {boundary}")
    if boundary.get("stream_proxy_captures", 0) != 0:
        raise AssertionError(f"Express abort request crossed as a stream: {boundary}")
    if boundary.get("json_fallbacks", 0) != 0:
        raise AssertionError(f"Express abort request used JSON fallback: {boundary}")
    if handles.get("handle_accesses_by_kind", {}).get("call", 0) < before_handles.get("handle_accesses_by_kind", {}).get("call", 0) + 1:
        raise AssertionError(f"Express abort request method call was not recorded: before={before_handles}, after={handles}")


def test_manifest_express_response_capture_keeps_writer_lifecycle_live():
    before_status = omnivm.status()
    before_boundary = before_status.get("boundary", {})
    before_handles = before_status.get("handles", {})
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {
                "op": "eval",
                "runtime": "javascript",
                "bind": "express_res",
                "code": (
                    "(() => { "
                    "const express = require('express'); "
                    "const http = require('http'); "
                    "const app = express(); "
                    "const req = new http.IncomingMessage(); "
                    "req.method = 'GET'; "
                    "req.url = '/express-response/42'; "
                    "req.headers = {'host': 'example.test'}; "
                    "Object.setPrototypeOf(req, express.request); "
                    "req.app = app; "
                    "const res = new http.ServerResponse(req); "
                    "Object.setPrototypeOf(res, express.response); "
                    "res.req = req; "
                    "res.app = app; "
                    "res.locals = {}; "
                    "res._omnivmWrites = []; "
                    "res._omnivmEnded = false; "
                    "const write = res.write.bind(res); "
                    "res.write = function(chunk, ...rest) { this._omnivmWrites.push(String(chunk)); return write(chunk, ...rest); }; "
                    "const end = res.end.bind(res); "
                    "res.end = function(chunk, ...rest) { if (typeof chunk !== 'undefined') this._omnivmWrites.push(String(chunk)); this._omnivmEnded = true; return end(chunk, ...rest); }; "
                    "globalThis.__omnivm_express_res = res; "
                    "return res; "
                    "})()"
                ),
            },
            {
                "op": "exec",
                "runtime": "python",
                "captures": {"express_res": "express_res"},
                "code": (
                    "express_res.status(207)\n"
                    "express_res.set('X-Poly', 'yes')\n"
                    "assert express_res.get('X-Poly') == 'yes', express_res.get('X-Poly')\n"
                    "assert express_res.statusCode == 207, express_res.statusCode\n"
                    "assert express_res.write('hello-') is True\n"
                    "express_res.end('done')"
                ),
            },
            {
                "op": "exec",
                "runtime": "javascript",
                "code": (
                    "const res = globalThis.__omnivm_express_res; "
                    "if (res.statusCode !== 207) throw new Error('bad Express response status: ' + res.statusCode); "
                    "if (res.get('X-Poly') !== 'yes') throw new Error('bad Express response header: ' + res.get('X-Poly')); "
                    "if (!res._omnivmEnded || !res.writableEnded) throw new Error('Express response writer was not ended'); "
                    "if (res._omnivmWrites.join('') !== 'hello-done') throw new Error('bad Express response writes: ' + res._omnivmWrites.join(''));"
                ),
            },
        ],
    }
    run_manifest_dict(manifest)

    after_status = omnivm.status()
    boundary = after_status.get("boundary", {})
    handles = after_status.get("handles", {})
    if boundary.get("resource_proxy_captures", 0) < before_boundary.get("resource_proxy_captures", 0) + 1:
        raise AssertionError(f"Express response did not cross as a live proxy: before={before_boundary}, after={boundary}")
    if boundary.get("stream_proxy_captures", 0) != before_boundary.get("stream_proxy_captures", 0):
        raise AssertionError(f"Express response crossed as a stream: before={before_boundary}, after={boundary}")
    if boundary.get("table_proxy_captures", 0) != before_boundary.get("table_proxy_captures", 0) or boundary.get("arrow_transfers", 0) != before_boundary.get("arrow_transfers", 0):
        raise AssertionError(f"Express response should not claim bulk transfer: before={before_boundary}, after={boundary}")
    if boundary.get("json_fallbacks", 0) != before_boundary.get("json_fallbacks", 0):
        raise AssertionError(f"Express response used JSON fallback: before={before_boundary}, after={boundary}")
    if handles.get("handle_accesses_by_kind", {}).get("call", 0) < before_handles.get("handle_accesses_by_kind", {}).get("call", 0) + 4:
        raise AssertionError(f"Express response writer methods were not recorded as proxy calls: before={before_handles}, after={handles}")


def test_manifest_express_response_write_after_end_reports_owner_error():
    before_status = omnivm.status()
    before_boundary = before_status.get("boundary", {})
    before_handles = before_status.get("handles", {})
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {
                "op": "eval",
                "runtime": "javascript",
                "bind": "express_res_after_end",
                "code": (
                    "(() => { "
                    "const express = require('express'); "
                    "const http = require('http'); "
                    "const app = express(); "
                    "const req = new http.IncomingMessage(); "
                    "req.method = 'GET'; "
                    "req.url = '/express-response/after-end'; "
                    "req.headers = {'host': 'example.test'}; "
                    "Object.setPrototypeOf(req, express.request); "
                    "req.app = app; "
                    "const res = new http.ServerResponse(req); "
                    "Object.setPrototypeOf(res, express.response); "
                    "res.req = req; "
                    "res.app = app; "
                    "res.locals = {}; "
                    "res._omnivmWrites = []; "
                    "res._omnivmErrors = []; "
                    "const write = res.write.bind(res); "
                    "res.write = function(chunk, ...rest) { "
                    "  if (!this.writableEnded) this._omnivmWrites.push(String(chunk)); "
                    "  return write(chunk, ...rest); "
                    "}; "
                    "const end = res.end.bind(res); "
                    "res.end = function(chunk, ...rest) { "
                    "  if (typeof chunk !== 'undefined') this._omnivmWrites.push(String(chunk)); "
                    "  return end(chunk, ...rest); "
                    "}; "
                    "res.on('error', (err) => { "
                    "  res._omnivmErrors.push({code: err && err.code, message: err && err.message, name: err && err.name}); "
                    "}); "
                    "globalThis.__omnivm_express_res_after_end = res; "
                    "return res; "
                    "})()"
                ),
            },
            {
                "op": "exec",
                "runtime": "python",
                "captures": {"express_res_after_end": "express_res_after_end"},
                "code": (
                    "express_res_after_end.status(209)\n"
                    "assert express_res_after_end.statusCode == 209, express_res_after_end.statusCode\n"
                    "express_res_after_end.end('done')\n"
                    "assert express_res_after_end.writableEnded is True, express_res_after_end.writableEnded\n"
                    "assert express_res_after_end.write('late') is False"
                ),
            },
            {
                "op": "exec",
                "runtime": "javascript",
                "async": True,
                "code": (
                    "await new Promise((resolve) => setTimeout(resolve, 25)); "
                    "const res = globalThis.__omnivm_express_res_after_end; "
                    "if (res.statusCode !== 209) throw new Error('bad Express after-end status: ' + res.statusCode); "
                    "if (!res.writableEnded) throw new Error('Express response did not end before late write'); "
                    "if (res._omnivmWrites.join('') !== 'done') throw new Error('late Express write reached owner body: ' + res._omnivmWrites.join('')); "
                    "if (res._omnivmErrors.length !== 1) throw new Error('Express response did not emit exactly one late-write error: ' + JSON.stringify(res._omnivmErrors)); "
                    "const err = res._omnivmErrors[0]; "
                    "if (err.code !== 'ERR_STREAM_WRITE_AFTER_END') throw new Error('bad Express late-write error code: ' + JSON.stringify(err)); "
                    "if (!String(err.message || '').includes('write after end')) throw new Error('bad Express late-write error message: ' + JSON.stringify(err));"
                ),
            },
        ],
    }
    run_manifest_dict(manifest)

    after_status = omnivm.status()
    boundary = after_status.get("boundary", {})
    handles = after_status.get("handles", {})
    resource_captures = boundary.get("resource_proxy_captures", 0)
    resource_capture_delta = resource_captures - before_boundary.get("resource_proxy_captures", 0)
    if resource_captures < 1 and resource_capture_delta < 1:
        raise AssertionError(f"Express response after-end writer did not cross as a live proxy: before={before_boundary}, after={boundary}")
    if boundary.get("stream_proxy_captures", 0) != before_boundary.get("stream_proxy_captures", 0):
        raise AssertionError(f"Express response after-end writer crossed as a stream: before={before_boundary}, after={boundary}")
    if boundary.get("json_fallbacks", 0) != before_boundary.get("json_fallbacks", 0):
        raise AssertionError(f"Express response after-end writer used JSON fallback: before={before_boundary}, after={boundary}")
    if handles.get("handle_accesses_by_kind", {}).get("call", 0) < before_handles.get("handle_accesses_by_kind", {}).get("call", 0) + 3:
        raise AssertionError(f"Express response after-end writer methods were not recorded as proxy calls: before={before_handles}, after={handles}")


