def test_manifest_js_plain_object_array_capture_uses_proxy_not_json():
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {
                "op": "eval",
                "runtime": "javascript",
                "bind": "js_payload",
                "code": "({path: '/js-object', items: ['first', 'second'], meta: {owner: 'js'}})",
            },
            {
                "op": "exec",
                "runtime": "python",
                "captures": {"js_payload": "js_payload"},
                "code": (
                    "assert js_payload.path == '/js-object', js_payload.path\n"
                    "assert js_payload.items[0] == 'first', js_payload.items[0]\n"
                    "js_payload.items[0] = 'python'\n"
                    "js_payload.meta.owner = 'python'\n"
                    "js_payload.extra = {'from': 'python'}"
                ),
            },
            {
                "op": "exec",
                "runtime": "ruby",
                "captures": {"js_payload": "js_payload"},
                "code": (
                    "raise \"bad JS nested array #{js_payload.items[0]}\" unless js_payload.items[0] == \"python\"; "
                    "raise \"bad JS nested object #{js_payload.meta.owner}\" unless js_payload.meta.owner == \"python\"; "
                    "raise \"bad Python-owned nested object #{js_payload.extra.from}\" unless js_payload.extra.from == \"python\"; "
                    "js_payload.items[1] = \"ruby\"; "
                    "js_payload.meta.owner = \"ruby\""
                ),
            },
            {
                "op": "exec",
                "runtime": "java",
                "captures": {"js_payload": "js_payload"},
                "code": (
                    "omnivm.OmniVM.HandleProxy payload = (omnivm.OmniVM.HandleProxy) omnivm.OmniVM.getCapture(\"js_payload\"); "
                    "omnivm.OmniVM.HandleProxy items = (omnivm.OmniVM.HandleProxy) payload.get(\"items\"); "
                    "omnivm.OmniVM.HandleProxy meta = (omnivm.OmniVM.HandleProxy) payload.get(\"meta\"); "
                    "if (!\"ruby\".equals(items.index(1))) throw new RuntimeException(\"bad JS array item: \" + items.index(1)); "
                    "if (!\"ruby\".equals(meta.get(\"owner\"))) throw new RuntimeException(\"bad JS nested owner: \" + meta.get(\"owner\")); "
                    "if (!items.set(\"0\", \"java\")) throw new RuntimeException(\"JS array set failed\"); "
                    "if (!meta.set(\"owner\", \"java\")) throw new RuntimeException(\"JS object nested set failed\");"
                ),
            },
            {
                "op": "exec",
                "runtime": "javascript",
                "code": (
                    "if (js_payload.items[0] !== 'java' || js_payload.items[1] !== 'ruby') throw new Error('bad JS array: ' + js_payload.items);"
                    "if (js_payload.meta.owner !== 'java') throw new Error('bad JS owner: ' + js_payload.meta.owner);"
                    "if (js_payload.extra.from !== 'python') throw new Error('bad Python-owned object: ' + js_payload.extra.from);"
                ),
            },
        ],
    }
    with tempfile.NamedTemporaryFile("w", suffix=".json", delete=False) as f:
        json.dump(manifest, f)
        path = f.name
    try:
        omnivm.run_manifest(path)
    finally:
        os.unlink(path)

    boundary = omnivm.status().get("boundary", {})
    if boundary.get("resource_proxy_captures", 0) < 3:
        raise AssertionError(f"JS plain object/array values did not cross as live proxies: {boundary}")
    if boundary.get("stream_proxy_captures", 0) != 0:
        raise AssertionError(f"JS plain object/array should not be mistaken for streams: {boundary}")
    if boundary.get("table_proxy_captures", 0) != 0 or boundary.get("arrow_transfers", 0) != 0:
        raise AssertionError(f"JS plain object/array should not claim bulk table transfer: {boundary}")
    if boundary.get("json_fallbacks", 0) != 0:
        raise AssertionError(f"JS plain object/array used JSON fallback: {boundary}")
    handles = omnivm.status().get("handles", {})
    for kind in ("property", "index", "mutation"):
        if handles.get("handle_accesses_by_kind", {}).get(kind, 0) < 1:
            raise AssertionError(f"JS plain object/array proxy did not record {kind} access: {handles}")


def test_manifest_js_collision_fields_stay_data_fields():
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {
                "op": "eval",
                "runtime": "javascript",
                "bind": "js_collision",
                "code": (
                    "({"
                    "items: ['first', 'second'], "
                    "keys: 'field-keys', "
                    "count: 7, "
                    "then: 'field-then', "
                    "length: 12, "
                    "get: 'field-get', "
                    "close: 'field-close'"
                    "})"
                ),
            },
            {
                "op": "exec",
                "runtime": "python",
                "captures": {"js_collision": "js_collision"},
                "code": (
                    "assert js_collision.items[0] == 'first', js_collision.items[0]\n"
                    "assert js_collision.keys == 'field-keys', js_collision.keys\n"
                    "assert js_collision.count == 7, js_collision.count\n"
                    "assert js_collision.then == 'field-then', js_collision.then\n"
                    "assert js_collision.length == 12, js_collision.length\n"
                    "assert js_collision.get == 'field-get', js_collision.get\n"
                    "assert js_collision.close == 'field-close', js_collision.close\n"
                    "js_collision.length = 13\n"
                    "js_collision.close = 'py-close'"
                ),
            },
            {
                "op": "exec",
                "runtime": "ruby",
                "captures": {"js_collision": "js_collision"},
                "code": (
                    "raise \"bad then field #{js_collision.then}\" unless js_collision.then == 'field-then'; "
                    "raise \"bad length field #{js_collision.length}\" unless js_collision.length == 13; "
                    "raise \"bad get field #{js_collision.get}\" unless js_collision.get == 'field-get'; "
                    "raise \"bad close field #{js_collision.close}\" unless js_collision.close == 'py-close'; "
                    "js_collision.keys = 'ruby-keys'"
                ),
            },
            {
                "op": "exec",
                "runtime": "java",
                "captures": {"js_collision": "js_collision"},
                "code": (
                    "omnivm.OmniVM.HandleProxy payload = (omnivm.OmniVM.HandleProxy) omnivm.OmniVM.getCapture(\"js_collision\"); "
                    "if (!\"field-then\".equals(String.valueOf(payload.get(\"then\")))) throw new RuntimeException(\"then field lost: \" + payload.get(\"then\")); "
                    "if (!\"13\".equals(String.valueOf(payload.get(\"length\")))) throw new RuntimeException(\"length field lost: \" + payload.get(\"length\")); "
                    "if (!\"field-get\".equals(String.valueOf(payload.get(\"get\")))) throw new RuntimeException(\"get field lost: \" + payload.get(\"get\")); "
                    "if (!\"py-close\".equals(String.valueOf(payload.get(\"close\")))) throw new RuntimeException(\"close field lost: \" + payload.get(\"close\")); "
                    "if (!payload.set(\"count\", 42)) throw new RuntimeException(\"count field set failed\"); "
                    "if (!payload.set(\"get\", \"java-get\")) throw new RuntimeException(\"get field set failed\");"
                ),
            },
            {
                "op": "exec",
                "runtime": "javascript",
                "code": (
                    "if (js_collision.items[0] !== 'first') throw new Error('items field lost: ' + js_collision.items); "
                    "if (js_collision.keys !== 'ruby-keys') throw new Error('keys field lost: ' + js_collision.keys); "
                    "if (js_collision.count !== 42) throw new Error('count field lost: ' + js_collision.count); "
                    "if (js_collision.then !== 'field-then') throw new Error('then field lost: ' + js_collision.then); "
                    "if (js_collision.length !== 13) throw new Error('length field lost: ' + js_collision.length); "
                    "if (js_collision.get !== 'java-get') throw new Error('get field lost: ' + js_collision.get); "
                    "if (js_collision.close !== 'py-close') throw new Error('close field lost: ' + js_collision.close);"
                ),
            },
        ],
    }
    run_manifest_dict(manifest)

    boundary = omnivm.status().get("boundary", {})
    if boundary.get("resource_proxy_captures", 0) < 1:
        raise AssertionError(f"JS collision object did not cross as a live proxy: {boundary}")
    if boundary.get("json_fallbacks", 0) != 0:
        raise AssertionError(f"JS collision object used JSON fallback: {boundary}")
    handles = omnivm.status().get("handles", {})
    accesses = handles.get("handle_accesses_by_kind", {})
    if accesses.get("property", 0) < 1 or accesses.get("mutation", 0) < 1:
        raise AssertionError(f"JS collision object did not record property and mutation access: {handles}")


def test_manifest_js_non_callable_then_field_is_not_thenable():
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {
                "op": "eval",
                "runtime": "python",
                "bind": "py_then_payload",
                "code": "{'then': 'field-then', 'length': 5, 'value': 'resolved-proxy'}",
            },
            {
                "op": "exec",
                "runtime": "javascript",
                "captures": {"py_then_payload": "py_then_payload"},
                "code": (
                    "globalThis.__omnivm_then_resolution = 'pending'; "
                    "if (py_then_payload.then !== 'field-then') throw new Error('then field lost before Promise.resolve: ' + py_then_payload.then); "
                    "Promise.resolve(py_then_payload).then(function(value) { "
                    "  globalThis.__omnivm_then_resolution = value.value; "
                    "});"
                ),
            },
            {
                "op": "exec",
                "runtime": "javascript",
                "code": (
                    "if (globalThis.__omnivm_then_resolution !== 'resolved-proxy') "
                    "throw new Error('non-callable then field was treated as a thenable or did not resolve to the proxy: ' + globalThis.__omnivm_then_resolution); "
                    "if (py_then_payload.then !== 'field-then') throw new Error('then field lost after Promise.resolve: ' + py_then_payload.then); "
                    "if (py_then_payload.length !== 5) throw new Error('length field lost after Promise.resolve: ' + py_then_payload.length);"
                ),
            },
        ],
    }
    run_manifest_dict(manifest)

    boundary = omnivm.status().get("boundary", {})
    handles = omnivm.status().get("handles", {})
    if boundary.get("resource_proxy_captures", 0) < 1:
        raise AssertionError(f"non-callable then payload did not cross as a live proxy: {boundary}")
    if boundary.get("json_fallbacks", 0) != 0:
        raise AssertionError(f"non-callable then payload used JSON fallback: {boundary}")
    if handles.get("handle_accesses_by_kind", {}).get("property", 0) < 1:
        raise AssertionError(f"non-callable then payload did not record proxy property access: {handles}")


def test_manifest_js_callable_then_field_requires_explicit_proxy_get():
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {
                "op": "exec",
                "runtime": "python",
                "code": (
                    "callable_then_calls = []\n"
                    "def callable_then(value=None, reject=None):\n"
                    "    callable_then_calls.append(value)\n"
                    "    return 'called:' + str(value)\n"
                    "py_callable_then_payload = {'then': callable_then, 'value': 'resolved-proxy'}"
                ),
            },
            {
                "op": "exec",
                "runtime": "javascript",
                "captures": {"py_callable_then_payload": "py_callable_then_payload"},
                "code": (
                    "globalThis.__omnivm_callable_then_resolution = 'pending'; "
                    "if (typeof py_callable_then_payload.then !== 'undefined') throw new Error('callable then should require explicit proxyGet'); "
                    "Promise.resolve(py_callable_then_payload).then(function(value) { "
                    "  globalThis.__omnivm_callable_then_resolution = value.value; "
                    "}); "
                    "const explicitThen = omnivm.proxyGet(py_callable_then_payload, 'then'); "
                    "if (typeof explicitThen !== 'function') throw new Error('explicit proxyGet did not expose callable then: ' + explicitThen); "
                    "const explicitResult = explicitThen('manual'); "
                    "if (explicitResult !== 'called:manual') throw new Error('bad explicit then result: ' + explicitResult);"
                ),
            },
            {
                "op": "exec",
                "runtime": "javascript",
                "code": (
                    "if (globalThis.__omnivm_callable_then_resolution !== 'resolved-proxy') "
                    "throw new Error('callable then field was treated as a thenable or did not resolve to proxy: ' + globalThis.__omnivm_callable_then_resolution);"
                ),
            },
            {
                "op": "exec",
                "runtime": "python",
                "code": "assert callable_then_calls == ['manual'], callable_then_calls",
            },
        ],
    }
    run_manifest_dict(manifest)

    boundary = omnivm.status().get("boundary", {})
    handles = omnivm.status().get("handles", {})
    if boundary.get("resource_proxy_captures", 0) < 1:
        raise AssertionError(f"callable then payload did not cross as a live proxy: {boundary}")
    if boundary.get("json_fallbacks", 0) != 0:
        raise AssertionError(f"callable then payload used JSON fallback: {boundary}")
    accesses = handles.get("handle_accesses_by_kind", {})
    if accesses.get("property", 0) < 1 or accesses.get("call", 0) < 1:
        raise AssertionError(f"callable then payload did not record property and call access: {handles}")


def test_manifest_js_map_capture_uses_proxy_not_json():
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {
                "op": "eval",
                "runtime": "javascript",
                "bind": "js_map",
                "code": "new Map([['alpha', 11], ['beta', 22]])",
            },
            {
                "op": "exec",
                "runtime": "python",
                "captures": {"js_map": "js_map"},
                "code": (
                    "assert js_map.size == 2, js_map.size\n"
                    "assert js_map.get('alpha') == 11, js_map.get('alpha')\n"
                    "js_map.set('gamma', 33)\n"
                    "assert js_map.get('gamma') == 33, js_map.get('gamma')"
                ),
            },
            {
                "op": "exec",
                "runtime": "ruby",
                "captures": {"js_map": "js_map"},
                "code": (
                    "raise \"bad JS Map size #{js_map.size}\" unless js_map.size == 3; "
                    "raise \"bad JS Map get #{js_map.get('gamma')}\" unless js_map.get('gamma') == 33; "
                    "js_map.set('delta', 44)"
                ),
            },
            {
                "op": "exec",
                "runtime": "javascript",
                "code": "if (js_map.get('delta') !== 44 || js_map.size !== 4) throw new Error('JS Map proxy mutation did not reach source runtime');",
            },
        ],
    }
    with tempfile.NamedTemporaryFile("w", suffix=".json", delete=False) as f:
        json.dump(manifest, f)
        path = f.name
    try:
        omnivm.run_manifest(path)
    finally:
        os.unlink(path)

    after = omnivm.status().get("boundary", {})
    if after.get("resource_proxy_captures", 0) < 1:
        raise AssertionError(f"JS Map did not cross as a live proxy: {after}")
    if after.get("table_proxy_captures", 0) != 0:
        raise AssertionError(f"JS Map should not claim a bulk table buffer: {after}")
    if after.get("arrow_transfers", 0) != 0:
        raise AssertionError(f"JS Map should not claim Arrow transfer: {after}")
    if after.get("stream_proxy_captures", 0) != 0:
        raise AssertionError(f"JS Map should not be mistaken for a stream: {after}")
    if after.get("json_fallbacks", 0) != 0:
        raise AssertionError(f"JS Map capture used JSON fallback: {after}")


def test_manifest_js_set_capture_uses_proxy_not_stream():
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {
                "op": "eval",
                "runtime": "javascript",
                "bind": "js_set",
                "code": "new Set(['alpha', 'beta'])",
            },
            {
                "op": "exec",
                "runtime": "python",
                "captures": {"js_set": "js_set"},
                "code": (
                    "assert js_set.size == 2, js_set.size\n"
                    "assert js_set.has('alpha') is True, js_set.has('alpha')\n"
                    "js_set.add('gamma')\n"
                    "assert js_set.has('gamma') is True, js_set.has('gamma')"
                ),
            },
            {
                "op": "exec",
                "runtime": "ruby",
                "captures": {"js_set": "js_set"},
                "code": (
                    "raise \"bad JS Set size #{js_set.size}\" unless js_set.size == 3; "
                    "raise \"bad JS Set has #{js_set.has('gamma')}\" unless js_set.has('gamma') == true; "
                    "js_set.add('delta')"
                ),
            },
            {
                "op": "exec",
                "runtime": "javascript",
                "code": "if (!js_set.has('delta') || js_set.size !== 4) throw new Error('JS Set proxy mutation did not reach source runtime');",
            },
        ],
    }
    with tempfile.NamedTemporaryFile("w", suffix=".json", delete=False) as f:
        json.dump(manifest, f)
        path = f.name
    try:
        omnivm.run_manifest(path)
    finally:
        os.unlink(path)

    after = omnivm.status().get("boundary", {})
    if after.get("resource_proxy_captures", 0) < 1:
        raise AssertionError(f"JS Set did not cross as a live proxy: {after}")
    if after.get("table_proxy_captures", 0) != 0:
        raise AssertionError(f"JS Set should not claim a bulk table buffer: {after}")
    if after.get("arrow_transfers", 0) != 0:
        raise AssertionError(f"JS Set should not claim Arrow transfer: {after}")
    if after.get("stream_proxy_captures", 0) != 0:
        raise AssertionError(f"JS Set should not be mistaken for a stream: {after}")
    if after.get("json_fallbacks", 0) != 0:
        raise AssertionError(f"JS Set capture used JSON fallback: {after}")


def test_manifest_zod_schema_capture_uses_proxy_not_json():
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {
                "op": "eval",
                "runtime": "javascript",
                "bind": "zod_schema",
                "code": (
                    "(() => { "
                    "const { z } = require('zod'); "
                    "return z.string().min(3).transform(s => s.toUpperCase()); "
                    "})()"
                ),
            },
            {
                "op": "exec",
                "runtime": "python",
                "captures": {"zod_schema": "zod_schema"},
                "code": (
                    "assert zod_schema.parse('poly') == 'POLY', zod_schema.parse('poly')\n"
                    "assert zod_schema.safeParse('vm').success is False, zod_schema.safeParse('vm').success"
                ),
            },
        ],
    }
    with tempfile.NamedTemporaryFile("w", suffix=".json", delete=False) as f:
        json.dump(manifest, f)
        path = f.name
    try:
        omnivm.run_manifest(path)
    finally:
        os.unlink(path)

    boundary = omnivm.status().get("boundary", {})
    if boundary.get("resource_proxy_captures", 0) < 1:
        raise AssertionError(f"Zod schema object did not cross as a live proxy: {boundary}")
    if boundary.get("json_fallbacks", 0) != 0:
        raise AssertionError(f"Zod schema object used JSON fallback: {boundary}")
    if boundary.get("table_proxy_captures", 0) != 0 or boundary.get("arrow_transfers", 0) != 0:
        raise AssertionError(f"Zod schema object should not claim bulk Arrow transfer: {boundary}")
    handles = omnivm.status().get("handles", {})
    if handles.get("handle_accesses_by_kind", {}).get("call", 0) < 1:
        raise AssertionError(f"Zod schema method calls were not recorded as proxy calls: {handles}")


def test_manifest_zod_parsed_collision_fields_stay_natural():
    before_status = omnivm.status()
    before_boundary = before_status.get("boundary", {})
    before_handles = before_status.get("handles", {})
    manifest = {
        "version": 1,
        "defaultRuntime": "javascript",
        "ops": [
            {
                "op": "exec",
                "runtime": "javascript",
                "code": (
                    "(() => { "
                    "const { z } = require('zod'); "
                    "const schema = z.object({"
                    "items: z.string(), "
                    "keys: z.string(), "
                    "count: z.number(), "
                    "then: z.string(), "
                    "length: z.number(), "
                    "get: z.string(), "
                    "close: z.string()"
                    "}); "
                    "globalThis.zod_collision_payload = schema.parse({"
                    "items: 'field-items', "
                    "keys: 'field-keys', "
                    "count: 7, "
                    "then: 'field-then', "
                    "length: 12, "
                    "get: 'field-get', "
                    "close: 'field-close'"
                    "});"
                    "})();"
                ),
            },
            {
                "op": "exec",
                "runtime": "python",
                "captures": {"zod_collision_payload": "zod_collision_payload"},
                "code": (
                    "assert zod_collision_payload.items == 'field-items', zod_collision_payload.items\n"
                    "assert zod_collision_payload.keys == 'field-keys', zod_collision_payload.keys\n"
                    "assert zod_collision_payload.count == 7, zod_collision_payload.count\n"
                    "assert zod_collision_payload.then == 'field-then', zod_collision_payload.then\n"
                    "assert zod_collision_payload.length == 12, zod_collision_payload.length\n"
                    "assert zod_collision_payload.get == 'field-get', zod_collision_payload.get\n"
                    "assert zod_collision_payload.close == 'field-close', zod_collision_payload.close\n"
                    "zod_collision_payload.items = 'python-items'\n"
                    "zod_collision_payload.then = 'python-then'\n"
                    "zod_collision_payload.length = 13"
                ),
            },
            {
                "op": "exec",
                "runtime": "ruby",
                "captures": {"zod_collision_payload": "zod_collision_payload"},
                "code": (
                    "raise \"bad Zod items #{zod_collision_payload.items}\" unless zod_collision_payload.items == 'python-items'; "
                    "raise \"bad Zod then #{zod_collision_payload.then}\" unless zod_collision_payload.then == 'python-then'; "
                    "raise \"bad Zod length #{zod_collision_payload.length}\" unless zod_collision_payload.length == 13; "
                    "zod_collision_payload.keys = 'ruby-keys'; "
                    "zod_collision_payload.close = 'ruby-close'"
                ),
            },
            {
                "op": "exec",
                "runtime": "java",
                "captures": {"zod_collision_payload": "zod_collision_payload"},
                "code": (
                    "omnivm.OmniVM.HandleProxy payload = (omnivm.OmniVM.HandleProxy) omnivm.OmniVM.getCapture(\"zod_collision_payload\"); "
                    "if (!\"python-items\".equals(String.valueOf(payload.get(\"items\")))) throw new RuntimeException(\"Zod Java items field lost: \" + payload.get(\"items\")); "
                    "if (!\"ruby-keys\".equals(String.valueOf(payload.get(\"keys\")))) throw new RuntimeException(\"Zod Java keys field lost: \" + payload.get(\"keys\")); "
                    "if (!\"field-get\".equals(String.valueOf(payload.get(\"get\")))) throw new RuntimeException(\"Zod Java get field lost: \" + payload.get(\"get\")); "
                    "if (!\"ruby-close\".equals(String.valueOf(payload.get(\"close\")))) throw new RuntimeException(\"Zod Java close field lost: \" + payload.get(\"close\")); "
                    "if (!payload.set(\"count\", 42)) throw new RuntimeException(\"Zod count set failed\"); "
                    "if (!payload.set(\"get\", \"java-get\")) throw new RuntimeException(\"Zod get set failed\");"
                ),
            },
            {
                "op": "exec",
                "runtime": "javascript",
                "code": (
                    "const payload = globalThis.zod_collision_payload; "
                    "if (payload.items !== 'python-items') throw new Error('Zod items field lost: ' + payload.items); "
                    "if (payload.keys !== 'ruby-keys') throw new Error('Zod keys field lost: ' + payload.keys); "
                    "if (payload.count !== 42) throw new Error('Zod count field lost: ' + payload.count); "
                    "if (payload.then !== 'python-then') throw new Error('Zod then field lost: ' + payload.then); "
                    "if (payload.length !== 13) throw new Error('Zod length field lost: ' + payload.length); "
                    "if (payload.get !== 'java-get') throw new Error('Zod get field lost: ' + payload.get); "
                    "if (payload.close !== 'ruby-close') throw new Error('Zod close field lost: ' + payload.close);"
                ),
            },
        ],
    }
    run_manifest_dict(manifest)

    after_status = omnivm.status()
    boundary = after_status.get("boundary", {})
    handles = after_status.get("handles", {})
    resource_captures = boundary.get("resource_proxy_captures", 0)
    resource_capture_delta = resource_captures - before_boundary.get("resource_proxy_captures", 0)
    if resource_captures < 1 and resource_capture_delta < 1:
        raise AssertionError(f"Zod parsed collision object did not cross as a live proxy: before={before_boundary}, after={boundary}")
    if boundary.get("json_fallbacks", 0) != before_boundary.get("json_fallbacks", 0):
        raise AssertionError(f"Zod parsed collision object used JSON fallback: before={before_boundary}, after={boundary}")
    if boundary.get("stream_proxy_captures", 0) != before_boundary.get("stream_proxy_captures", 0):
        raise AssertionError(f"Zod parsed collision object crossed as stream: before={before_boundary}, after={boundary}")
    if boundary.get("table_proxy_captures", 0) != before_boundary.get("table_proxy_captures", 0):
        raise AssertionError(f"Zod parsed collision object crossed as table: before={before_boundary}, after={boundary}")
    accesses = handles.get("handle_accesses_by_kind", {})
    before_accesses = before_handles.get("handle_accesses_by_kind", {})
    if accesses.get("property", 0) < before_accesses.get("property", 0) + 1:
        raise AssertionError(f"Zod parsed collision object did not record property access: before={before_handles}, after={handles}")
    if accesses.get("mutation", 0) < before_accesses.get("mutation", 0) + 1:
        raise AssertionError(f"Zod parsed collision object did not record mutation access: before={before_handles}, after={handles}")


def test_validation_error_fidelity_popular_libraries():
    cases = [
        (
            "zod",
            "javascript",
            (
                "const { z } = require('zod'); "
                "z.object({age:z.number().min(1), name:z.string()}).parse({age:0});"
            ),
            ["ZodError", "too_small", "age", "invalid_type", "name"],
            {"runtime": "javascript", "type": "ZodError", "message": "["},
        ),
        (
            "javascript error cause",
            "javascript",
            "throw new Error('outer', {cause: new TypeError('inner')})",
            ["Error", "outer", "Caused by", "TypeError", "inner"],
            {"runtime": "javascript", "type": "Error", "message": "outer", "cause_type": "TypeError", "cause_message": "inner"},
        ),
        (
            "pydantic",
            "python",
            (
                "from pydantic import BaseModel, Field\n"
                "class User(BaseModel):\n"
                "    age:int=Field(gt=0)\n"
                "    name:str\n"
                "User(age=0)"
            ),
            ["ValidationError", "age", "greater_than", "name", "missing"],
            {"runtime": "python", "type": "ValidationError", "message": "2 validation errors for User"},
        ),
        (
            "marshmallow",
            "python",
            (
                "from marshmallow import Schema, fields, validate\n"
                "class User(Schema):\n"
                "    age = fields.Integer(required=True, validate=validate.Range(min=1))\n"
                "    name = fields.String(required=True)\n"
                "User().load({'age': 0})"
            ),
            ["ValidationError", "age", "greater than or equal to 1", "name", "Missing data"],
            {"runtime": "python", "type": "ValidationError", "message": "age"},
        ),
        (
            "django forms",
            "python",
            (
                "from django.conf import settings\n"
                "if not settings.configured: settings.configure(USE_I18N=False, SECRET_KEY='x')\n"
                "from django import forms\n"
                "class Signup(forms.Form):\n"
                "    age=forms.IntegerField(min_value=1)\n"
                "    name=forms.CharField(required=True)\n"
                "form=Signup({'age':'0'})\n"
                "from django.core.exceptions import ValidationError\n"
                "raise ValidationError(form.errors.as_json())"
            ),
            ["ValidationError", "age", "min_value", "name", "required"],
            {"runtime": "python", "type": "ValidationError", "message": "age"},
        ),
        (
            "sqlalchemy",
            "python",
            (
                "from sqlalchemy import Column, Integer, MetaData, String, Table, create_engine\n"
                "engine = create_engine('sqlite:///:memory:')\n"
                "metadata = MetaData()\n"
                "users = Table('users', metadata, Column('id', Integer, primary_key=True), Column('name', String, unique=True))\n"
                "metadata.create_all(engine)\n"
                "with engine.begin() as conn:\n"
                "    conn.execute(users.insert().values(name='ada'))\n"
                "    conn.execute(users.insert().values(name='ada'))"
            ),
            ["IntegrityError", "UNIQUE constraint failed", "users.name", "INSERT INTO users"],
            {"runtime": "python", "type": "IntegrityError", "message": "UNIQUE constraint failed"},
        ),
        (
            "java cause chain",
            "java",
            (
                '((java.util.concurrent.Callable<String>)(() -> { '
                'throw new RuntimeException("outer", new IllegalArgumentException("inner")); '
                '})).call()'
            ),
            ["java.lang.RuntimeException", "outer", "Caused by", "java.lang.IllegalArgumentException", "inner"],
            {"runtime": "java", "type": "java.lang.RuntimeException", "message": "outer", "cause_type": "java.lang.IllegalArgumentException", "cause_message": "inner"},
        ),
        (
            "ruby activerecord",
            "ruby",
            "require 'active_record'; raise ActiveRecord::RecordInvalid.new(nil)",
            ["ActiveRecord::RecordInvalid", "Record invalid"],
            {"runtime": "ruby", "type": "ActiveRecord::RecordInvalid", "message": "Record invalid"},
        ),
    ]
    for name, runtime, code, expected, structured in cases:
        try:
            omnivm.call(runtime, code)
        except omnivm.RuntimeError as exc:
            text = str(exc)
            missing = [part for part in expected if part not in text]
            if missing:
                raise AssertionError(f"{name} error lost details {missing}: {text}") from exc
            if exc.runtime != structured["runtime"]:
                raise AssertionError(f"{name} error runtime = {exc.runtime!r}, want {structured['runtime']!r}: {text}") from exc
            if exc.type != structured["type"]:
                raise AssertionError(f"{name} error type = {exc.type!r}, want {structured['type']!r}: {text}") from exc
            want_boundary = f"call[{runtime}]"
            if exc.boundary_path != want_boundary:
                raise AssertionError(f"{name} error boundary path = {exc.boundary_path!r}, want {want_boundary!r}: {text}") from exc
            if structured["message"] not in exc.message:
                raise AssertionError(f"{name} error message = {exc.message!r}, want containing {structured['message']!r}: {text}") from exc
            if "traceback" in structured and structured["traceback"] not in exc.traceback:
                raise AssertionError(f"{name} error traceback = {exc.traceback!r}, want containing {structured['traceback']!r}: {text}") from exc
            envelope = exc.to_dict()
            json.dumps(envelope)
            if envelope.get("runtime") != exc.runtime or envelope.get("type") != exc.type:
                raise AssertionError(f"{name} structured envelope lost runtime/type: {envelope!r}") from exc
            if envelope.get("message") != exc.message or envelope.get("traceback") != exc.traceback:
                raise AssertionError(f"{name} structured envelope lost message/traceback: {envelope!r}") from exc
            if envelope.get("boundary_path") != exc.boundary_path:
                raise AssertionError(f"{name} structured envelope lost boundary path: {envelope!r}") from exc
            if envelope.get("original_error_handle") is not None:
                raise AssertionError(f"{name} structured envelope should not invent an error handle: {envelope!r}") from exc
            if "cause_type" in structured:
                if not exc.cause_chain:
                    raise AssertionError(f"{name} error lost cause chain: {text}") from exc
                cause = exc.cause_chain[0]
                if cause.get("type") != structured["cause_type"] or structured["cause_message"] not in cause.get("message", ""):
                    raise AssertionError(f"{name} error cause = {cause!r}, want {structured}: {text}") from exc
                if not envelope.get("cause_chain") or envelope["cause_chain"][0] != cause:
                    raise AssertionError(f"{name} structured envelope lost cause chain: {envelope!r}") from exc
        else:
            raise AssertionError(f"{name} did not raise an error")


def test_javascript_native_sqlalchemy_error_fields_cross_runtime_call():
    python_source = (
        "from sqlalchemy import Column, Integer, MetaData, String, Table, create_engine\n"
        "engine = create_engine('sqlite:///:memory:')\n"
        "metadata = MetaData()\n"
        "users = Table('users', metadata, Column('id', Integer, primary_key=True), Column('name', String, unique=True))\n"
        "metadata.create_all(engine)\n"
        "with engine.begin() as conn:\n"
        "    conn.execute(users.insert().values(name='ada'))\n"
        "    conn.execute(users.insert().values(name='ada'))\n"
    )
    result = omnivm.call(
        "javascript",
        f'''
(() => {{
  try {{
    omnivm.call("python", {json.dumps(python_source)});
  }} catch (err) {{
    return JSON.stringify({{
      isError: err instanceof Error,
      runtime: err.runtime,
      type: err.type,
      message: err.message,
      traceback: err.traceback,
      boundaryPath: err.boundaryPath,
      causeChain: err.causeChain,
      originalErrorHandle: err.originalErrorHandle
    }});
  }}
  return JSON.stringify({{missing: true}});
}})()
'''
    )
    envelope = json.loads(result)
    if envelope.get("missing"):
        raise AssertionError("JS SQLAlchemy IntegrityError path did not raise")
    if not envelope.get("isError"):
        raise AssertionError(f"JS catch did not receive a native Error for SQLAlchemy failure: {envelope}")
    if envelope.get("runtime") != "python":
        raise AssertionError(f"JS SQLAlchemy error runtime lost: {envelope}")
    if envelope.get("type") != "IntegrityError":
        raise AssertionError(f"JS SQLAlchemy error type lost: {envelope}")
    detail = (envelope.get("message") or "") + "\n" + (envelope.get("traceback") or "")
    for part in ("UNIQUE constraint failed", "users.name", "INSERT INTO users"):
        if part not in detail:
            raise AssertionError(f"JS SQLAlchemy error detail {part!r} lost: {envelope}")
    if "Traceback" not in envelope.get("traceback", ""):
        raise AssertionError(f"JS SQLAlchemy error traceback lost: {envelope}")
    if envelope.get("boundaryPath") != "call[python]":
        raise AssertionError(f"JS SQLAlchemy boundary path lost: {envelope}")
    if envelope.get("originalErrorHandle") is not None:
        raise AssertionError(f"JS SQLAlchemy error should not invent original handle: {envelope}")


