def test_manifest_validation_error_preserves_runtime_type_and_boundary_path():
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {
                "op": "exec",
                "runtime": "python",
                "code": (
                    "from pydantic import BaseModel, Field\n"
                    "class User(BaseModel):\n"
                    "    age:int=Field(gt=0)\n"
                    "    name:str\n"
                    "User(age=0)\n"
                ),
            },
        ],
    }
    try:
        run_manifest_dict(manifest)
    except omnivm.RuntimeError as exc:
        text = str(exc)
        if exc.runtime != "python":
            raise AssertionError(f"manifest validation error runtime = {exc.runtime!r}: {text}") from exc
        if exc.type != "ValidationError":
            raise AssertionError(f"manifest validation error type = {exc.type!r}: {text}") from exc
        for part in ("2 validation errors for User", "age", "greater_than", "name", "missing"):
            if part not in text and part not in exc.message and part not in exc.traceback:
                raise AssertionError(f"manifest validation error lost {part!r}: {text}") from exc
        if not exc.boundary_path or "execute manifest" not in exc.boundary_path or "exec[python]" not in exc.boundary_path:
            raise AssertionError(f"manifest validation error boundary path = {exc.boundary_path!r}: {text}") from exc
        if "Traceback" not in exc.traceback or 'File "<string>", line 5' not in exc.traceback:
            raise AssertionError(f"manifest validation error traceback lost source frame: {exc.traceback!r}") from exc
    else:
        raise AssertionError("manifest validation error did not raise")


def test_manifest_go_cshared_wrapped_error_preserves_cause_chain():
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {
                "op": "func_def",
                "name": "fail_go",
                "params": [],
                "body": [],
                "bodyRuntime": "go",
                "source": (
                    "package polyfunc\n\n"
                    "import (\n"
                    "\t\"errors\"\n"
                    "\t\"fmt\"\n"
                    ")\n\n"
                    "func Fail() (string, error) {\n"
                    "\tinner := errors.New(\"inner layer\")\n"
                    "\treturn \"\", fmt.Errorf(\"outer layer: %w\", inner)\n"
                    "}\n"
                ),
                "exports": ["Fail"],
            },
            {
                "op": "exec",
                "runtime": "python",
                "code": "fail_go()",
            },
        ],
    }
    try:
        run_manifest_dict(manifest)
    except omnivm.RuntimeError as exc:
        text = str(exc)
        if "outer layer: inner layer" not in text:
            raise AssertionError(f"Go wrapped error lost outer message: {text}") from exc
        if "Caused by: inner layer" not in text:
            raise AssertionError(f"Go wrapped error lost cause text: {text}") from exc
        if not exc.cause_chain:
            raise AssertionError(f"Go wrapped error did not populate cause_chain: {text}") from exc
        cause = exc.cause_chain[0]
        if cause.get("message") != "inner layer":
            raise AssertionError(f"Go wrapped error cause = {cause!r}: {text}") from exc
        if not exc.boundary_path or "execute manifest" not in exc.boundary_path or "exec[python]" not in exc.boundary_path:
            raise AssertionError(f"Go wrapped error boundary path = {exc.boundary_path!r}: {text}") from exc
    else:
        raise AssertionError("Go c-shared wrapped error did not raise")


