                    "        self.pulls += 1\n"
                    "        if self.index >= len(self.chunks):\n"
                    "            raise StopIteration\n"
                    "        chunk = self.chunks[self.index]\n"
                    "        self.index += 1\n"
                    "        return chunk\n"
