                    "    bytes: 0,\n"
                    "    aborted: false,\n"
                    "    reqAborted: false,\n"
                    "    reqClosed: false,\n"
                    "    multerFinished: false,\n"
                    "    multerError: null,\n"
                    "    fileSize: null,\n"
                    "    uploadClosed: false,\n"
                    "    uploadError: null,\n"
