def test_manifest_node_web_stream_pipe_to_abort_reenters_python_and_cancels_owner():
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {
                "op": "exec",
                "runtime": "python",
                "code": (
                    "node_pipe_state = {'idx': 0, 'pulls': 0, 'cancelled': False, 'cancel_reason': None}\n"
                    "node_pipe_chunks = ['first', 'second', 'third']\n"
                    "def node_pipe_source_next():\n"
                    "    node_pipe_state['pulls'] += 1\n"
                    "    if node_pipe_state['idx'] >= len(node_pipe_chunks):\n"
                    "        return None\n"
                    "    chunk = node_pipe_chunks[node_pipe_state['idx']]\n"
                    "    node_pipe_state['idx'] += 1\n"
                    "    return chunk\n"
                    "def node_pipe_source_cancel(reason):\n"
                    "    node_pipe_state['cancelled'] = True\n"
                    "    node_pipe_state['cancel_reason'] = str(reason)\n"
                    "    return 'cancelled'\n"
                ),
            },
            {
                "op": "exec",
                "runtime": "javascript",
                "async": True,
                "code": (
                    "const {ReadableStream, WritableStream} = require('node:stream/web');\n"
                    "const abortController = new AbortController();\n"
                    "globalThis.nodeWebPipeAbortState = {\n"
                    "  writes: [],\n"
                    "  sinkAborted: false,\n"
                    "  sinkAbortReason: null,\n"
                    "  cancelReason: null,\n"
                    "  pipeError: null,\n"
                    "  locked: null\n"
                    "};\n"
                    "const source = new ReadableStream({\n"
                    "  pull(controller) {\n"
                    "    const chunk = omnivm.call('python', 'node_pipe_source_next()');\n"
                    "    if (chunk === null || chunk === undefined) {\n"
                    "      controller.close();\n"
                    "      return;\n"
                    "    }\n"
                    "    controller.enqueue(chunk);\n"
                    "  },\n"
                    "  cancel(reason) {\n"
                    "    const text = reason === undefined ? 'undefined' : String(reason);\n"
                    "    globalThis.nodeWebPipeAbortState.cancelReason = text;\n"
                    "    omnivm.call('python', 'node_pipe_source_cancel(' + JSON.stringify(text) + ')');\n"
                    "  }\n"
                    "}, {highWaterMark: 0});\n"
                    "const sink = new WritableStream({\n"
                    "  write(chunk) {\n"
                    "    globalThis.nodeWebPipeAbortState.writes.push(String(chunk));\n"
                    "    if (globalThis.nodeWebPipeAbortState.writes.length === 1) {\n"
                    "      abortController.abort('client-stop');\n"
                    "    }\n"
                    "  },\n"
                    "  abort(reason) {\n"
                    "    globalThis.nodeWebPipeAbortState.sinkAborted = true;\n"
                    "    globalThis.nodeWebPipeAbortState.sinkAbortReason = reason === undefined ? 'undefined' : String(reason);\n"
                    "  }\n"
                    "});\n"
                    "try {\n"
                    "  await source.pipeTo(sink, {signal: abortController.signal});\n"
                    "} catch (err) {\n"
                    "  globalThis.nodeWebPipeAbortState.pipeError = err && err.name ? err.name + ':' + err.message : String(err);\n"
                    "}\n"
                    "globalThis.nodeWebPipeAbortState.locked = source.locked;"
                ),
            },
            {
                "op": "exec",
                "runtime": "javascript",
                "code": (
                    "const state = globalThis.nodeWebPipeAbortState; "
                    "if (state.writes.join('|') !== 'first') throw new Error('Node Web pipeTo wrote after abort: ' + JSON.stringify(state)); "
                    "if (!state.sinkAborted) throw new Error('Node Web pipeTo sink did not observe abort: ' + JSON.stringify(state)); "
                    "if (state.sinkAbortReason !== 'client-stop') throw new Error('bad Node Web pipeTo sink abort reason: ' + JSON.stringify(state)); "
                    "if (state.cancelReason !== 'client-stop') throw new Error('bad Node Web pipeTo source cancel reason: ' + JSON.stringify(state)); "
                    "if (state.locked) throw new Error('Node Web pipeTo left source locked: ' + JSON.stringify(state));"
                ),
            },
            {
                "op": "exec",
                "runtime": "python",
                "code": (
                    "if not node_pipe_state['cancelled']:\n"
                    "    raise AssertionError(f\"Node Web pipeTo abort did not cancel Python owner: {node_pipe_state!r}\")\n"
                    "if node_pipe_state['cancel_reason'] != 'client-stop':\n"
                    "    raise AssertionError(f\"bad Node Web pipeTo Python cancel reason: {node_pipe_state!r}\")\n"
                    "if node_pipe_state['pulls'] > 2:\n"
                    "    raise AssertionError(f\"Node Web pipeTo over-pulled after abort: {node_pipe_state!r}\")\n"
                ),
            },
        ],
    }
    run_manifest_dict(manifest)


def test_manifest_httpx_response_stream_early_cancel_releases_owner():
    before_status = omnivm.status()
    before_handles = before_status.get("handles", {})
    setup = r'''
import httpx

class OwnerStream(httpx.SyncByteStream):
    def __init__(self):
        self.closed = False
        self.cancelled = False
        self.iterations = 0

    def __iter__(self):
        self.iterations += 1
        yield b"first"
        yield b"second"

    def close(self):
        self.closed = True
        self.cancelled = True

owner_stream = OwnerStream()
httpx_response = httpx.Response(200, stream=owner_stream)

def httpx_body_iter():
    try:
        yield from httpx_response.iter_bytes()
    finally:
        httpx_response.close()

httpx_body = httpx_body_iter()
'''
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {"op": "exec", "runtime": "python", "code": setup},
            {
                "op": "exec",
                "runtime": "javascript",
                "code": (
                    "const it = httpx_body[Symbol.iterator](); "
                    "const first = it.next(); "
                    "const asText = (value) => String.fromCharCode(...Array.from(value)); "
                    "if (first.done || asText(first.value) !== 'first') throw new Error('bad httpx first chunk: ' + JSON.stringify(first)); "
                    "omnivm.call('python', 'httpx_body.close()');"
                ),
                "captures": {"httpx_body": "httpx_body"},
            },
            {
                "op": "exec",
                "runtime": "python",
                "code": (
                    "assert owner_stream.iterations == 1, owner_stream.iterations\n"
                    "assert owner_stream.closed, 'httpx stream was not closed after early cancel'\n"
                    "assert owner_stream.cancelled, 'httpx stream did not observe cancellation'"
                ),
            },
        ],
    }
    run_manifest_dict(manifest)

    after_status = omnivm.status()
    boundary = after_status.get("boundary", {})
    handles = after_status.get("handles", {})
    if boundary.get("stream_proxy_captures", 0) < before_status.get("boundary", {}).get("stream_proxy_captures", 0) + 1:
        raise AssertionError(f"httpx response body lost stream proxy state: before={before_status.get('boundary', {})}, after={boundary}")
    if boundary.get("json_fallbacks", 0) != before_status.get("boundary", {}).get("json_fallbacks", 0):
        raise AssertionError(f"httpx response body used JSON fallback: before={before_status.get('boundary', {})}, after={boundary}")
    released = handles.get("released", 0) - before_handles.get("released", 0)
    scoped = handles.get("scope_releases", 0) - before_handles.get("scope_releases", 0)
    if handles.get("handle_accesses_by_kind", {}).get("stream", 0) < before_handles.get("handle_accesses_by_kind", {}).get("stream", 0) + 1:
        raise AssertionError(f"httpx response body did not record stream access: before={before_handles}, after={handles}")
    if released < 1 and scoped < 1:
        raise AssertionError(f"httpx response body did not release on early cancel: before={before_handles}, after={handles}")
    if handles.get("live", 0) != before_handles.get("live", 0):
        raise AssertionError(f"httpx response body early-cancel leaked live handles: before={before_handles}, after={handles}")


def test_manifest_requests_response_stream_early_cancel_releases_owner():
    before_status = omnivm.status()
    before_handles = before_status.get("handles", {})
    setup = r'''
import requests
import threading
import time
from http.server import BaseHTTPRequestHandler, ThreadingHTTPServer

requests_state = {
    "requests": 0,
    "chunks_started": 0,
    "handler_done": False,
    "handler_error": "",
}

class RequestsStreamHandler(BaseHTTPRequestHandler):
    def log_message(self, *_args):
        pass

    def do_GET(self):
        requests_state["requests"] += 1
        self.send_response(200)
        self.send_header("Content-Type", "text/plain")
        self.end_headers()
        try:
            self.wfile.write(b"first\n")
            self.wfile.flush()
            requests_state["chunks_started"] += 1
            time.sleep(0.2)
            self.wfile.write(b"second\n")
            self.wfile.flush()
            requests_state["chunks_started"] += 1
        except (BrokenPipeError, ConnectionResetError) as exc:
            requests_state["handler_error"] = type(exc).__name__
        finally:
            requests_state["handler_done"] = True

requests_server = ThreadingHTTPServer(("127.0.0.1", 0), RequestsStreamHandler)
requests_thread = threading.Thread(target=requests_server.serve_forever, daemon=True)
requests_thread.start()
requests_response = requests.get(
    f"http://127.0.0.1:{requests_server.server_address[1]}/stream",
    stream=True,
    timeout=5,
)

class RequestsLineOwner:
    def __init__(self, response):
        self.response = response
        self.iterator = response.iter_lines()
        self.iterations = 0
        self.lines_pulled = 0
        self.closed = False
        self.cancelled = False

    def __iter__(self):
        self.iterations += 1
        return self

    def __next__(self):
        line = next(self.iterator)
        self.lines_pulled += 1
        return line.decode("utf-8")

    def close(self):
        self.closed = True
        self.cancelled = True
        self.response.close()

requests_body = RequestsLineOwner(requests_response)
'''
    cleanup = r'''
assert requests_body.iterations == 1, requests_body.iterations
assert requests_body.lines_pulled == 1, requests_body.lines_pulled
assert requests_body.closed, 'requests stream was not closed after early cancel'
assert requests_body.cancelled, 'requests stream did not observe cancellation'
assert requests_response.raw.closed, 'requests response raw stream stayed open'
assert requests_state["requests"] == 1, requests_state
requests_server.shutdown()
requests_server.server_close()
requests_thread.join(timeout=2)
'''
    manifest = {
        "version": 1,
        "defaultRuntime": "python",
        "ops": [
            {"op": "exec", "runtime": "python", "code": setup},
            {
                "op": "exec",
                "runtime": "javascript",
                "captures": {"requests_body": "requests_body"},
                "code": (
                    "const it = requests_body[Symbol.iterator](); "
                    "const first = it.next(); "
                    "if (first.done || first.value !== 'first') throw new Error('bad requests first line: ' + JSON.stringify(first)); "
                    "if (requests_body.cancel('client-stop') !== true) throw new Error('requests cancel failed');"
                ),
            },
            {"op": "exec", "runtime": "python", "code": cleanup},
        ],
    }
    run_manifest_dict(manifest)

    after_status = omnivm.status()
    boundary = after_status.get("boundary", {})
    handles = after_status.get("handles", {})
    if boundary.get("stream_proxy_captures", 0) < before_status.get("boundary", {}).get("stream_proxy_captures", 0):
        raise AssertionError(f"requests response body lost stream proxy state: before={before_status.get('boundary', {})}, after={boundary}")
    if boundary.get("json_fallbacks", 0) != before_status.get("boundary", {}).get("json_fallbacks", 0):
        raise AssertionError(f"requests response body used JSON fallback: before={before_status.get('boundary', {})}, after={boundary}")
    if handles.get("handle_accesses_by_kind", {}).get("stream", 0) < before_handles.get("handle_accesses_by_kind", {}).get("stream", 0) + 1:
        raise AssertionError(f"requests response body did not record stream access: before={before_handles}, after={handles}")
    if handles.get("explicit_releases", 0) < before_handles.get("explicit_releases", 0) + 1:
        raise AssertionError(f"requests response body did not release on early cancel: before={before_handles}, after={handles}")
    if handles.get("live", 0) != before_handles.get("live", 0):
        raise AssertionError(f"requests response body early-cancel leaked live handles: before={before_handles}, after={handles}")


