                    "  res.on('close', () => { state.responseClosed = true; });\n"
                    "  res.writeHead(200, {'content-type': 'text/plain'});\n"
                    "  res.write('first');\n"
                    "  state.chunks += 1;\n"
                    "  setTimeout(() => {\n"
                    "    if (!res.destroyed && !res.writableEnded) {\n"
                    "      state.chunks += 1;\n"
                    "      res.write('second');\n"
                    "    }\n"
                    "  }, 200);\n"
                    "});\n"
